mapper.select:
/* SQL ID : listLessonProgress 설 명 : 학습진도관리 목록 조회 */ WITH SBJ_LIST AS ( SELECT * FROM ( SELECT A.SBJCT_YR , A.SBJCT_SMSTR , A.SMSTR_CHRT_ID AS SMSTR_CHRT_REF_ID , SMSTR.ORG_ID , A.DEPT_ID , A.SBJCT_ID , A.SBJCTNM , A.DVCLAS_NO , A.DELYN FROM TB_LMS_SBJCT_OFRNG A JOIN TB_LMS_SMSTR_CHRT SMSTR ON A.SBJCT_REF_TYCD = 'SMSTR_CHRT' AND A.SMSTR_CHRT_ID = SMSTR.SMSTR_CHRT_ID UNION ALL SELECT A.SBJCT_YR , A.SBJCT_SMSTR , A.CRS_MSTR_ID AS SMSTR_CHRT_REF_ID , CRS.ORG_ID , A.DEPT_ID , A.SBJCT_ID , A.SBJCTNM , A.DVCLAS_NO , A.DELYN FROM TB_LMS_SBJCT_OFRNG A JOIN TB_LMS_CRS_MSTR CRS ON A.SBJCT_REF_TYCD = 'CRS_MSTR' AND A.CRS_MSTR_ID = CRS.CRS_MSTR_ID ) WHERE 1=1 AND DELYN = 'N'
AND SBJCT_YR = #{sbjctYr}
AND SMSTR_CHRT_REF_ID = #{smstrChrtId}
AND ORG_ID = #{orgId}
AND DEPT_ID = #{deptId}
AND SBJCT_ID = #{sbjctOfrngId}
),
OPEN_WK_LIST AS ( SELECT ORG.ORGNM , A.* , B.LCTR_WKNO_SCHDL_ID FROM SBJ_LIST A JOIN TB_LMS_LCTR_WKNO_SCHDL B ON A.SBJCT_ID = B.SBJCT_ID AND B.DELYN = 'N' AND (FN_DT() > B.LCTR_WKNO_EYMD OR FN_DT() BETWEEN B.LCTR_WKNO_SYMD AND B.LCTR_WKNO_EYMD) LEFT JOIN TB_LMS_ORG ORG ON A.ORG_ID = ORG.ORG_ID ),
OPEN_WK_CNT AS ( SELECT SBJCT_ID , COUNT(*) AS OPEN_WK_CNT FROM OPEN_WK_LIST GROUP BY SBJCT_ID ),
STD_LIST AS ( SELECT A.SBJCT_ID , B.USER_ID , USR.USERNM , B.SCYR FROM SBJ_LIST A JOIN TB_LMS_ATNDLC B ON A.SBJCT_ID = B.SBJCT_ID JOIN TB_LMS_USER USR ON B.USER_ID = USR.USER_ID WHERE 1=1 AND B.AUDITYN = 'N' ) SELECT ROW_NUMBER() OVER(ORDER BY A.SBJCT_YR ASC, A.SBJCT_SMSTR ASC, A.ORGNM DESC, A.DEPTNM ASC, A.SBJCTNM) AS LINE_NO , A.* FROM ( SELECT
OWL.SBJCT_YR , OWL.SBJCT_SMSTR , OWL.ORGNM
, NVL(DEPT.DEPTNM, '—') AS DEPTNM , OWL.SBJCTNM , OWL.DVCLAS_NO , STS.USER_ID , USR.USERNM , USR.SCYR , OWK.OPEN_WK_CNT
, COUNT(CASE WHEN NVL(STS.PRGRT,0) > 0 THEN STS.LCTR_WKNO_SCHDL_ID END ) AS LRN_WK_CNT , ROUND( COUNT(CASE WHEN NVL(STS.PRGRT,0) > 0 THEN STS.LCTR_WKNO_SCHDL_ID END ) / NULLIF(OWK.OPEN_WK_CNT, 0) * 100 , 2) AS PRGRT FROM OPEN_WK_LIST OWL JOIN OPEN_WK_CNT OWK ON OWL.SBJCT_ID = OWK.SBJCT_ID JOIN STD_LIST USR ON OWL.SBJCT_ID = USR.SBJCT_ID LEFT JOIN TB_LMS_BYWK_USER_LRN_STS STS ON OWL.LCTR_WKNO_SCHDL_ID = STS.LCTR_WKNO_SCHDL_ID AND USR.USER_ID = STS.USER_ID LEFT JOIN TB_LMS_DEPT DEPT ON OWL.DEPT_ID = DEPT.DEPT_ID WHERE 1=1
AND LRN_WK_CNT > 0
AND LRN_WK_CNT >= 0
AND PRGRT >= #{searchFrom}
AND PRGRT < #{searchTo}
GROUP BY OWL.SBJCT_ID , OWL.ORG_ID , OWL.SBJCT_YR , OWL.SBJCT_SMSTR , OWL.ORGNM , DEPT.DEPT_ID , DEPTNM , OWL.SBJCTNM , OWL.DVCLAS_NO , STS.USER_ID , USR.USERNM , USR.SCYR , OWK.OPEN_WK_CNT ) A ORDER BY LINE_NO DESC

/* SQL ID : listLessonProgressExcel 설 명 : 학습진도관리 현황 목록 조회 */ WITH PROF_COURSE_T AS ( SELECT A.SBJCT_ID FROM TB_LMS_SBJCT A JOIN SBJCT_PROF B ON A.SBJCT_ID = B.SBJCT_ID AND B.PROF_TYCD = 'PROFESSOR' AND B.RPRSYN = 'Y' AND B.USER_ID = #{userId} WHERE A.DELYN = 'N' AND A.CRS_ID NOT LIKE '%JLPT%' AND A.SBJCT_TYCD = 'UNI' AND A.SBJCT_ID = #{creYear} AND A.CRS_ID = #{creTerm}
AND A.SBJCT_ID = #{crsCreCd}
AND A.DEPT_CD = #{deptCd}
AND A.UNIV_CD = #{uniCd}
) SELECT ROW_NUMBER() OVER(ORDER BY A.USERNM) AS LINE_NO , A.* FROM ( SELECT A.SBJCT_ID , A.USER_ID , A.USERNM , A.ENTR_YY , A.DEPTNM , A.MOBILE_NO , A.EMAIL , A.CRS_CRE_CNT , A.ALL_SCHEDULE_CNT , A.STUDY_SCHEDULE_CNT , NVL(ROUND(A.STUDY_SCHEDULE_CNT / NULLIF(A.ALL_SCHEDULE_CNT, 0) * 100, 2), 0) AS STUDY_PERSENT FROM ( SELECT A.SBJCT_ID , A.USER_ID , A.USERNM , A.ENTR_YY , A.DEPTNM , A.MOBILE_NO , A.EMAIL , COUNT(DISTINCT A.STD_ID) AS CRS_CRE_CNT , COUNT(DISTINCT B.LCTR_SCHDL_ID) AS ALL_SCHEDULE_CNT , SUM(CASE WHEN C.ATNDLC_STSCD IN ('COMPLETE', 'LATE') THEN 1 ELSE 0 END) AS STUDY_SCHEDULE_CNT FROM ( SELECT A.SBJCT_ID , B.STD_ID , B.AUDITYN , C.USER_ID , C.USERNM , C.ENTR_YY , C.DEPTNM , C.MOBILE_NO , C.EMAIL FROM PROF_COURSE_T A JOIN TB_LMS_ATNDLC_SBJCT B ON A.SBJCT_ID = B.SBJCT_ID AND B.ATNDLC_STSCD = 'S' AND B.AUDITYN = 'N' JOIN TB_LMS_USR C ON B.USER_ID = C.USER_ID ) A LEFT JOIN ( SELECT A.SBJCT_ID , B.LCTR_SCHDL_ID FROM PROF_COURSE_T A JOIN TB_LMS_SBJCT_LCTR_SCHDL B ON A.SBJCT_ID = B.SBJCT_ID AND B.DELYN = 'N' AND ( B.LCTR_WKNO_GBNCD IN ('02', '03') -- 세미나 주차 포함 OR EXISTS ( SELECT 1 FROM TB_LMS_SBJCT_LCTR_CONTS AA WHERE AA.LCTR_SCHDL_ID = B.LCTR_SCHDL_ID AND ( AA.LCTR_CONTS_GBNCD = 'VIDEO' OR ( AA.LCTR_CONTS_GBNCD = 'VIDEO_LINK' AND EXISTS (SELECT 1 FROM SBJCT_LCTR_CONTS_PAGE WHERE SBJCT_LCTR_CONTS_ID = AA.SBJCT_LCTR_CONTS_ID) ) ) AND AA.DELYN = 'N' AND AA.PRG_RFLTYN = 'Y' ) ) AND FN_DTTM() >= NVL(B.LCTR_RCG_SYMD, B.LCTR_SYMD) ) B ON A.SBJCT_ID = B.SBJCT_ID LEFT JOIN TB_LMS_LESSON_STUDY_STATE C ON A.STD_ID = C.STD_ID AND B.LCTR_SCHDL_ID = C.LCTR_SCHDL_ID
GROUP BY A.SBJCT_ID, A.USER_ID, A.USERNM, A.ENTR_YY, A.DEPTNM, A.MOBILE_NO, A.EMAIL ) A ) A WHERE 1=1
AND A.STUDY_PERSENT != 100
AND A.STUDY_PERSENT >= #{searchFrom}
AND A.STUDY_PERSENT < #{searchTo}

/* SQL ID : selectLessonProgress 설 명 : 학습진도관리 수강생, 평균 진도율 조회 */ SELECT SUM(CASE WHEN X.GBN = 'MY' THEN X.STD_CNT ELSE 0 END) AS MY_STD_CNT , ROUND(SUM(CASE WHEN X.GBN = 'MY' THEN IFNULL(ROUND(X.STUDY_CNT / (X.SCHEDULE_CNT * X.STD_CNT) * 100) / X.CRS_CNT, 0) ELSE 0 END)) AS MY_LESSON_AVG , SUM(CASE WHEN X.GBN = 'ALL' THEN X.STD_CNT ELSE 0 END) AS ALL_STD_CNT , ROUND(SUM(CASE WHEN X.GBN = 'ALL' THEN IFNULL(ROUND(X.STUDY_CNT / (X.SCHEDULE_CNT * X.STD_CNT) * 100) / X.CRS_CNT, 0) ELSE 0 END)) AS ALL_LESSON_AVG FROM ( SELECT 'MY' AS GBN , IFNULL((SELECT COUNT(*) FROM TB_LMS_ATNDLC_SBJCT WHERE ATNDLC_STSCD = 'S' AND SBJCT_ID = A.SBJCT_ID), 0) AS STD_CNT , IFNULL((SELECT COUNT(*) FROM TB_LMS_SBJCT_LCTR_SCHDL WHERE SBJCT_ID = A.SBJCT_ID AND OYN = 'Y' AND DELYN = 'N'), 0) AS SCHEDULE_CNT , IFNULL((SELECT COUNT(AA.STD_ID) FROM TB_LMS_LESSON_STUDY_STATE AA JOIN TB_LMS_ATNDLC_SBJCT BB ON AA.STD_ID = BB.STD_ID AND AA.SBJCT_ID = BB.SBJCT_ID AND BB.ATNDLC_STSCD = 'S' WHERE AA.SBJCT_ID = A.SBJCT_ID AND AA.ATNDLC_STSCD IN ('STUDY', 'LATE')), 0) AS STUDY_CNT , COUNT(1) OVER() AS CRS_CNT FROM SBJCT_PROF A JOIN TB_LMS_SBJCT B ON A.SBJCT_ID = B.SBJCT_ID AND B.DELYN = 'N' WHERE A.USER_ID = #{userId} AND A.RPRSYN = 'Y' AND B.SBJCT_ID = #{creYear} AND B.CRS_ID = #{creTerm}
AND B.UNIV_CD = #{uniCd}
AND B.DEPT_CD = #{deptCd}
UNION ALL SELECT 'ALL' AS GBN , IFNULL((SELECT COUNT(*) FROM TB_LMS_ATNDLC_SBJCT WHERE ATNDLC_STSCD = 'S' AND SBJCT_ID = A.SBJCT_ID), 0) AS STD_CNT , IFNULL((SELECT COUNT(*) FROM TB_LMS_SBJCT_LCTR_SCHDL WHERE SBJCT_ID = A.SBJCT_ID AND OYN = 'Y' AND DELYN = 'N'), 0) AS SCHEDULE_CNT , IFNULL((SELECT COUNT(AA.STD_ID) FROM TB_LMS_LESSON_STUDY_STATE AA JOIN TB_LMS_ATNDLC_SBJCT BB ON AA.STD_ID = BB.STD_ID AND AA.SBJCT_ID = BB.SBJCT_ID AND BB.ATNDLC_STSCD = 'S' WHERE AA.SBJCT_ID = A.SBJCT_ID AND AA.ATNDLC_STSCD IN ('STUDY', 'LATE')), 0) AS STUDY_CNT , COUNT(1) OVER() AS CRS_CNT FROM TB_LMS_SBJCT A WHERE A.DELYN = 'N' AND A.SBJCT_ID = #{creYear} AND A.CRS_ID = #{creTerm}
AND A.UNIV_CD = #{uniCd}
AND A.DEPT_CD = #{deptCd}
) X

/* SQL ID : LessonDAO.selectLessonProgressTotalStatus 설 명 : 학습진도관리 전체현황 */ WITH SBJCT_LIST AS ( SELECT * FROM ( SELECT A.SBJCT_YR , A.SBJCT_SMSTR , SMSTR.SMSTR_CHRT_ID AS SMSTR_CHRT_REF_ID , SMSTR.ORG_ID , A.DEPT_ID , A.SBJCT_ID , A.SBJCTNM , A.DVCLAS_NO , A.DELYN FROM TB_LMS_SBJCT A JOIN TB_LMS_SMSTR_CHRT SMSTR ON A.SBJCT_REF_TYCD = 'SMSTR_CHRT' AND A.SMSTR_CHRT_ID = SMSTR.SMSTR_CHRT_ID UNION ALL SELECT A.SBJCT_YR , A.SBJCT_SMSTR , CRS.CRS_MSTR_ID AS SMSTR_CHRT_REF_ID , CRS.ORG_ID , A.DEPT_ID , A.SBJCT_ID , A.SBJCTNM , A.DVCLAS_NO , A.DELYN FROM TB_LMS_SBJCT A JOIN TB_LMS_CRS_MSTR CRS ON A.SBJCT_REF_TYCD = 'CRS_MSTR' AND A.CRS_MSTR_ID = CRS.CRS_MSTR_ID ) WHERE 1=1 AND DELYN = 'N' ) ,TTL_STD_CNT AS ( SELECT COUNT(A.USER_ID) AS TTL_STD_CNT FROM TB_LMS_LRN_PRGRT A JOIN SBJCT_LIST B ON A.SBJCT_ID = B.SBJCT_ID
AND B.ORG_ID = #{orgId}
), TTL_PRGRT AS ( SELECT SUM(A.PRGRT) AS TTL_SUM_PRGRT FROM TB_LMS_LRN_PRGRT A JOIN SBJCT_LIST B ON A.SBJCT_ID = B.SBJCT_ID
AND B.ORG_ID = #{orgId}
) SELECT A.TTL_STD_CNT , NVL( ROUND(B.TTL_SUM_PRGRT / A.TTL_STD_CNT, 2),0) AS AVG_LRN_PRGRT FROM TTL_STD_CNT A , TTL_PRGRT B

/* SQL ID : LessonDAO.listLessonProgressStatusBatch 설 명 : 학습진도관리 목록 (배치) */ SELECT ROW_NUMBER() OVER(ORDER BY A.DEPT_CD_ODR, A.USERNM) AS LINE_NO , A.* FROM ( SELECT A.USER_ID , MAX(A.UNIV_CD) AS UNIV_CD , MAX(OCUNIV.CDNM) AS UNIV_GBN_NM , MAX(B.DEPT_CD) AS DEPT_CD , MAX(E.DEPTNM) AS DEPTNM , MAX(B.USERNM) AS USERNM , MAX(B.ENTR_YY) AS ENTR_YY , MAX(B.ENTR_HY) AS ENTR_HY , MAX(CASE WHEN B.ENTR_TM_GBN = '10' THEN '1' WHEN B.ENTR_TM_GBN = '20' THEN '2' END) AS ENTR_TM_GBN , MAX(B.ENTR_GBN_NM) AS ENTR_GBN_NM , MAX(B.EMAIL) AS EMAIL , MAX(B.MOBILE_NO) AS MOBILE_NO , COUNT(1) AS CRS_CNT , MAX(A.SCYR) AS SCYR , SUM(A.LRN_WKNO) AS LRN_WKNO , SUM(A.TOT_WEEK_CNT) AS TOT_WEEK_CNT , ROUND(NVL(AVG(A.PRGRT), 0), 2) AS PRGRT , MAX(A.MOD_DTTM) AS MOD_DTTM , MAX(D.SBJCTNM) AS SBJCTNM , MAX(D.DVCLAS_NO) AS DVCLAS_NO , MAX(E.DEPT_CD_ODR) AS DEPT_CD_ODR FROM TB_LMS_LRN_PRGRT A JOIN TB_LMS_USR B ON A.USER_ID = B.USER_ID JOIN TB_LMS_SBJCT D ON A.SBJCT_ID = D.SBJCT_ID AND D.DELYN = 'N' LEFT JOIN TB_HOME_USER_DEPT_CD E ON E.ORG_ID = #{orgId} AND E.DEPT_CD = B.DEPT_CD LEFT JOIN TB_ORG_CODE OCUNIV ON OCUNIV.ORG_ID = #{orgId} AND OCUNIV.CTGRCD = 'UNIV_GBNCD' AND OCUNIV.CD = A.UNIV_GBNCD WHERE A.SBJCT_ID = #{haksaYear} AND A.CRS_ID = #{haksaTerm} AND A.SBJCT_ID NOT LIKE '%JLPT%'
AND A.UNIV_CD = #{uniCd}
AND A.UNIV_GBNCD = #{univGbn}
AND B.DEPT_CD = #{deptCd}
AND A.SBJCT_ID = #{crsCreCd}
AND ( A.USER_ID = #{searchValue} OR LOWER(B.USERNM) = LOWER(#{searchValue}) )
AND D.CRS_ID = #{crsCd}
GROUP BY A.USER_ID ) A WHERE 1 = 1
AND NVL(A.PRGRT, 0) = 0 AND TOT_WEEK_CNT > 0
AND NVL(A.PRGRT, 0) >= #{searchFrom}
AND NVL(A.PRGRT, 0) < #{searchTo}
ORDER BY A.DEPT_CD_ODR, A.USERNM

/* SQL ID : LessonDAO.listLessonProgressStatusWeekBatch 설 명 : 학습진도관리 목록 주차별 (배치) */ SELECT ROW_NUMBER() OVER(ORDER BY A.DEPT_CD_ODR, A.USERNM) AS LINE_NO , A.* , ( SELECT COUNT(1) FROM TB_LMS_ATNDLC_SBJCT AA JOIN TB_LMS_SBJCT BB ON AA.SBJCT_ID = BB.SBJCT_ID AND BB.DELYN = 'N' AND BB.SBJCT_ID = #{haksaYear} AND BB.CRS_ID = #{haksaTerm} AND BB.SBJCT_TYCD = 'UNI' AND BB.SBJCT_ID NOT LIKE '%JLPT%' WHERE AA.USER_ID = A.USER_ID AND AA.ATNDLC_STSCD = 'S' AND AA.AUDITYN = 'N' ) AS CRS_CNT FROM ( SELECT /*+ INDEX(A tb_learner_week_prog_LESSON_SCHEDULE_ORDER) */ A.USER_ID , MAX(A.UNIV_CD) AS UNIV_CD
, MAX(B.DEPT_CD) AS DEPT_CD , MAX(E.DEPTNM) AS DEPTNM , MAX(B.USERNM) AS USERNM , MAX(B.ENTR_YY) AS ENTR_YY , MAX(B.ENTR_HY) AS ENTR_HY , MAX(CASE WHEN B.ENTR_TM_GBN = '10' THEN '1' WHEN B.ENTR_TM_GBN = '20' THEN '2' END) AS ENTR_TM_GBN , MAX(B.ENTR_GBN_NM) AS ENTR_GBN_NM , MAX(B.EMAIL) AS EMAIL , MAX(B.MOBILE_NO) AS MOBILE_NO , MAX(A.SCYR) AS SCYR , ROUND(NVL(AVG(A.PRGRT), 0), 2) AS PRGRT , SUM(CASE WHEN NVL(PRGRT, 0) < 50 THEN 1 ELSE 0 END) AS UNDER50_CRS_CNT , MAX(A.MOD_DTTM) AS MOD_DTTM , MAX(D.SBJCTNM) AS SBJCTNM , MAX(D.DVCLAS_NO) AS DVCLAS_NO , MAX(E.DEPT_CD_ODR) AS DEPT_CD_ODR FROM TB_LEARNER_WEEK_PROG A JOIN TB_LMS_USR B ON A.USER_ID = B.USER_ID JOIN TB_LMS_SBJCT D ON A.SBJCT_ID = D.SBJCT_ID AND D.DELYN = 'N' LEFT JOIN TB_HOME_USER_DEPT_CD E ON E.ORG_ID = #{orgId} AND E.DEPT_CD = B.DEPT_CD
WHERE A.SBJCT_ID = #{haksaYear} AND A.CRS_ID = #{haksaTerm} AND A.SBJCT_ID NOT LIKE '%JLPT%'
AND A.UNIV_CD = #{uniCd}
AND B.DEPT_CD = #{deptCd}
AND A.SBJCT_ID = #{crsCreCd}
AND ( A.USER_ID = #{searchValue} OR LOWER(B.USERNM) = LOWER(#{searchValue}) )
AND D.CRS_ID = #{crsCd}
AND A.LCTR_SCHDL_SEQ = #{lessonScheduleOrder} GROUP BY A.USER_ID ) A WHERE 1 = 1
AND NVL(A.PRGRT, 0) < 100
AND NVL(A.PRGRT, 0) >= #{searchFrom}
AND NVL(A.PRGRT, 0) < #{searchTo}
ORDER BY A.DEPT_CD_ODR, A.USERNM

mapper.sql:
SELECT A.SBJCT_ID , A.CRS_ID , A.SBJCTNM , A.DVCLAS_NO , A.DEPT_CD , A.USER_ID , A.USERNM , B.LCTR_TOC_LRN_SCNDS , B.LCTR_NOTE , B.LCTR_NOTE_PVSNYN , B.LCTR_SCHDLNM , B.LCTR_SCHDL_SEQ , C.LCTR_CLASTMNM , C.LCTR_CLASTM_SEQ , D.LCTR_CONTSNM , D.LCTR_CONTS_SEQ , D.LCTR_CONTS_GBNCD FROM ( SELECT A.SBJCT_ID , A.CRS_ID , A.SBJCTNM , A.DVCLAS_NO , A.DEPT_CD , C.USER_ID , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = C.USER_ID) AS USERNM FROM TB_LMS_SBJCT A JOIN TB_LMS_CRS B ON A.CRS_ID = B.CRS_ID AND B.ORG_ID = #{orgId} LEFT JOIN SBJCT_PROF C ON A.SBJCT_ID = C.SBJCT_ID AND C.PROF_TYCD = 'PROFESSOR' AND C.RPRSYN = 'Y' WHERE A.DELYN = 'N' AND A.SBJCT_ID = #{creYear} AND A.CRS_ID = #{creTerm}
AND A.SBJCT_TYCD IN
#{item}
AND A.UNIV_CD = #{uniCd}
AND A.UNIV_GBNCD = #{univGbn}
AND A.DEPT_CD = #{deptCd}
AND A.SBJCT_ID = #{crsCreCd}
AND ( LOWER(A.CRS_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(A.SBJCTNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER((SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = C.USER_ID)) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
) A JOIN TB_LMS_SBJCT_LCTR_SCHDL B ON A.SBJCT_ID = B.SBJCT_ID AND B.DELYN = 'N' JOIN TB_LMS_SBJCT_LCTR_CLASTM C ON B.LCTR_SCHDL_ID = C.LCTR_SCHDL_ID JOIN TB_LMS_SBJCT_LCTR_CONTS D ON C.SBJCT_LCTR_CLASTM_ID = D.SBJCT_LCTR_CLASTM_ID AND D.DELYN = 'N'

mapper.select:
/* SQL ID : LessonDAO.listCntsUsage 설 명 : 콘텐츠 현황 목록 */ SELECT ROW_NUMBER() OVER(ORDER BY A.CRS_ID, A.SBJCTNM, A.DVCLAS_NO, A.LCTR_SCHDL_SEQ, A.LCTR_CLASTM_SEQ, A.LCTR_CONTS_SEQ) AS LINE_NO , A.* , (SELECT DEPTNM FROM TB_HOME_USER_DEPT_CD WHERE ORG_ID = #{orgId} AND DEPT_CD = A.DEPT_CD) AS DEPTNM FROM (
) A
WHERE ROWNUM > #{firstIndex} AND ROWNUM <= #{listScale}
